(() => {
    type ICircularDeep = {name: string; embedded: {hello: string; child?: ICircularDeep}};
    return {build: () => createValidate<ICircularDeep>(), buildErrors: () => noErrs(createGetValidationErrors<ICircularDeep>())};
  })()

() => {
    const icd = RT.circular((self) =>
      RT.object({
        name: RT.string(),
        embedded: RT.object({hello: RT.string(), child: RT.optional(self)}),
      })
    );
    return createValidate(icd);
  }

(() => {
    type ICircularDeep = {name: string; embedded: {hello: string; child?: ICircularDeep}};
    return {
      build: () => {
        const check = typia.createIs<ICircularDeep>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<ICircularDeep>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Recursive((This) =>
      Type.Object({
        name: Type.String(),
        embedded: Type.Object({hello: Type.String(), child: Type.Optional(This)}),
      })
    )
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({name: z.string(), embedded: z.object({hello: z.string(), child: z.lazy(() => schema).optional()})});
    return schema;
  }))
